<?php
namespace App\Domain\Shops;
use App\Domain\Inventory\Capacity\PendingRewardCapacityService;use App\Domain\Inventory\Instances\ItemInstanceService;use App\Domain\Inventory\InventoryService;use App\Domain\Inventory\ItemClassification;use App\Domain\Shops\Data\ShopSaleResult;use App\Domain\Shops\Exceptions\ShopSaleConflictException;use App\Domain\Shops\Exceptions\ShopSaleSourceNotFoundException;use App\Domain\Shops\Exceptions\ShopSaleUnavailableException;use App\Domain\Shops\Exceptions\ShopSaleValidationException;use App\Domain\Wallet\GoldReasonCode;use App\Domain\Wallet\WalletService;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Character;use App\Models\CharacterEquipment;use App\Models\CharacterItem;use App\Models\CharacterWallet;use App\Models\Item;use App\Models\ItemInstance;use App\Models\Shop;use App\Models\ShopSale;use Carbon\CarbonImmutable;use Illuminate\Auth\Access\AuthorizationException;use Illuminate\Support\Facades\DB;
final class ShopSaleService{const SNAPSHOT_VERSION=1;private $access;private $pricing;private $classification;private $inventory;private $instances;private $wallet;private $capacity;private $items;public function __construct(ShopAccessService $a,ShopSalePricingService $p,ItemClassification $c,InventoryService $i,ItemInstanceService $is,WalletService $w,PendingRewardCapacityService $cap,NpcSaleItemValidator $items){$this->access=$a;$this->pricing=$p;$this->classification=$c;$this->inventory=$i;$this->instances=$is;$this->wallet=$w;$this->capacity=$cap;$this->items=$items;}public function sell(ShopSaleCommand $cmd){try{return DB::transaction(function()use($cmd){$character=Character::whereKey($cmd->character->id)->lockForUpdate()->firstOrFail();if((int)$character->user_id!==(int)$cmd->user->id)throw new AuthorizationException();$existing=ShopSale::where('idempotency_key',$cmd->idempotencyKey)->lockForUpdate()->first();if($existing)return$this->replay($existing,$cmd);$shop=Shop::with(['npc','locations'])->whereKey($cmd->shop->id)->lockForUpdate()->firstOrFail();$now=CarbonImmutable::now('UTC');$zone=$this->access->authorize($shop,$character,$cmd->zoneId,$now);if(!$shop->buys_items)throw new ShopSaleUnavailableException();$row=null;$instance=null;if($cmd->sourceType===ShopSaleSourceType::STACK){$row=CharacterItem::whereKey($cmd->characterItemId)->where('character_id',$character->id)->lockForUpdate()->first();if(!$row)throw new ShopSaleSourceNotFoundException();$itemId=$row->item_id;}else{$instance=ItemInstance::where('uuid',$cmd->itemInstanceUuid)->where('character_id',$character->id)->lockForUpdate()->first();if(!$instance)throw new ShopSaleSourceNotFoundException();CharacterEquipment::where('item_instance_id',$instance->id)->lockForUpdate()->get();$itemId=$instance->item_id;if($cmd->quantity!==1)throw new ShopSaleValidationException();}$item=Item::whereKey($itemId)->lockForUpdate()->firstOrFail();if($item->status!==CatalogStatus::ACTIVE)throw new ShopSaleValidationException();$this->items->validate($item);$kind=$this->classification->classify($item);if(($row&&$kind!==ItemClassification::STACKABLE)||($instance&&$kind!==ItemClassification::UNIQUE))throw new ShopSaleValidationException();if($row&&(int)$row->quantity-(int)$row->locked_quantity<$cmd->quantity)throw new ShopSaleValidationException();$price=$this->pricing->calculate((int)$item->sell_price,(int)$shop->purchase_rate_basis_points,$cmd->quantity);$wallet=CharacterWallet::where('character_id',$character->id)->lockForUpdate()->first();if(!$wallet){$wallet=new CharacterWallet(['character_id'=>$character->id]);$wallet->gold_balance=0;$wallet->save();}$input=['character_id'=>(int)$character->id,'shop_id'=>(int)$shop->id,'source_type'=>$cmd->sourceType,'character_item_id'=>$row?(int)$row->id:null,'item_instance_uuid'=>$instance?$instance->uuid:null,'quantity'=>$cmd->quantity,'zone_id'=>$zone];$sale=ShopSale::create(['shop_id'=>$shop->id,'character_id'=>$character->id,'item_id'=>$item->id,'item_instance_id'=>$instance?$instance->id:null,'character_item_id_snapshot'=>$row?$row->id:null,'source_type'=>$cmd->sourceType,'quantity_sold'=>$cmd->quantity,'unit_gold'=>$price->unitGold(),'total_gold'=>$price->totalGold(),'idempotency_key'=>$cmd->idempotencyKey,'sold_at'=>$now,'metadata'=>['input'=>$input]]);if($row)$this->inventory->withdrawMultipleLocked($character,collect([$item->id=>$item]),[$item->id=>$cmd->quantity],collect([$row]));else$this->instances->markSoldToShopLocked($character,$instance,$sale,$now);$gold=$this->wallet->creditLocked($character,$price->totalGold(),GoldReasonCode::SHOP_SALE,'Venta a Shop','shop_sale',$sale->id,$cmd->idempotencyKey);$capacity=$this->capacity->snapshot($character,$now)->toArray();$remaining=$row?(int)(CharacterItem::whereKey($row->id)->value('quantity')?:0):null;$sale->metadata=['snapshot_version'=>self::SNAPSHOT_VERSION,'input'=>$input,'source'=>['type'=>$cmd->sourceType,'character_item_id'=>$row?(int)$row->id:null,'item_instance_uuid'=>$instance?$instance->uuid:null],'item'=>['code'=>$item->code,'name'=>$item->name,'item_type'=>$item->item_type,'rarity'=>$item->rarity,'classification'=>$kind],'instance'=>$instance?['uuid'=>$instance->uuid,'refinement_level'=>(int)$instance->refinement_level,'status_before'=>'available','origin_type'=>$instance->origin_type,'origin_id'=>(int)$instance->origin_id,'origin_unit_index'=>(int)$instance->origin_unit_index]:null,'pricing'=>['item_sell_price'=>(int)$item->sell_price,'shop_purchase_rate_basis_points'=>(int)$shop->purchase_rate_basis_points,'unit_gold'=>$price->unitGold(),'total_gold'=>$price->totalGold()],'wallet'=>['balance_before'=>$gold->balanceBefore(),'balance_after'=>$gold->balanceAfter()],'inventory'=>['remaining_quantity'=>$remaining,'item_removed'=>$instance?true:$remaining===0,'slots_used_after'=>$capacity['current_used_slots'],'slots_capacity'=>$capacity['effective_capacity']],'context'=>['zone_id'=>$zone]];$sale->save();return ShopSaleResult::fromSale($sale,false);},3);}catch(ShopSaleSourceNotFoundException $e){throw$e;}catch(AuthorizationException $e){throw$e;}catch(ShopSaleConflictException $e){throw$e;}catch(ShopSaleUnavailableException $e){throw$e;}catch(\InvalidArgumentException $e){throw new ShopSaleValidationException($e->getMessage(),0,$e);}}private function replay(ShopSale $sale,ShopSaleCommand $cmd){$expected=['character_id'=>(int)$cmd->character->id,'shop_id'=>(int)$cmd->shop->id,'source_type'=>$cmd->sourceType,'character_item_id'=>$cmd->characterItemId,'item_instance_uuid'=>$cmd->itemInstanceUuid,'quantity'=>$cmd->quantity,'zone_id'=>$cmd->zoneId];if(!isset($sale->metadata['input'])||$sale->metadata['input']!=$expected)throw new ShopSaleConflictException();return ShopSaleResult::fromSale($sale,true);}}
